CREATE TABLE CHINHANH (IDCN TEXT PRIMARY KEY NOT NULL, TENCNHANH TEXT NOT NULL, HOTLINE TEXT, DIACHI TEXT);
CREATE TABLE CHUCVU (IDCV TEXT PRIMARY KEY NOT NULL, TENCV TEXT NOT NULL);
CREATE TABLE PHONGBAN (IDPB TEXT PRIMARY KEY NOT NULL, TENPB TEXT NOT NULL, DIACHI TEXT, NGAYTHANHLAP TEXT);
CREATE TABLE TRINHDO (IDTD TEXT PRIMARY KEY NOT NULL, TENTD TEXT NOT NULL, CHUYENNGANH TEXT);
CREATE TABLE NHANVIEN (IDNV TEXT PRIMARY KEY NOT NULL, TENNV TEXT NOT NULL, GIOITINH TEXT, NGAYSINH TEXT, CCCD TEXT, EMAIL TEXT, DIENTHOAI TEXT, DIACHI TEXT, DANTOC TEXT, TONGIAO TEXT, HONNHAN TEXT, TRINHDO TEXT NOT NULL, CHUCVU TEXT NOT NULL, PHONGBAN TEXT NOT NULL, CHINHANH TEXT NOT NULL, IsDeleted INTEGER DEFAULT 0);
CREATE TABLE LOAIHD (IDLOAI TEXT PRIMARY KEY NOT NULL, TENLOAI TEXT NOT NULL, THOIHAN INTEGER, BHYT TEXT, BHXH TEXT, BHTN TEXT);
CREATE TABLE HOPDONG (SODH TEXT PRIMARY KEY NOT NULL, NGAYKY TEXT, NGAYBATDAU TEXT, NGAYKETTHUC TEXT, LUONGCOBAN REAL, TRANGTHAI TEXT, IDNV TEXT NOT NULL, LOAIHD TEXT NOT NULL, IsDeleted INTEGER DEFAULT 0);
CREATE TABLE BANGCHAMCONG (IDBC TEXT PRIMARY KEY NOT NULL, IDNV TEXT NOT NULL, THANG INTEGER, NAM INTEGER, SOGIOTANGCA REAL, SONGAYNGHI INTEGER, SONGAYDITRE INTEGER, TONGNGAYLAM INTEGER, TRANGTHAI TEXT);
CREATE TABLE LOAICONG (IDLC TEXT PRIMARY KEY NOT NULL, TENLC TEXT NOT NULL, MOTA TEXT);
CREATE TABLE CHITIET_BANGCONG (IDCT TEXT PRIMARY KEY NOT NULL, IDBC TEXT NOT NULL, NGAYLAM INTEGER, LOAICONG TEXT NOT NULL);
CREATE TABLE BANGLUONG (IDBL TEXT PRIMARY KEY NOT NULL, IDBC TEXT NOT NULL, LUONGCOBAN REAL, LUONGTHUCTE REAL, THUETNCN REAL, LUONGTHUONG REAL, PHUCAPCHUCVU REAL, KHOANTRUBAOHIEM REAL, PHUCAPKHAC REAL, KHOANTRUKHAC REAL, THUCNHAN REAL);
CREATE TABLE UNGVIEN (IDUV TEXT PRIMARY KEY, TENUV TEXT, GIOITINH TEXT, NGAYSINH TEXT, CCCD TEXT, EMAIL TEXT, DIACHI TEXT, DIENTHOAI TEXT, DANTOC TEXT, TONGIAO TEXT, HONNHAN TEXT, TRINHDO TEXT, TRANGTHAI TEXT, LUONG_DEAL REAL);
CREATE TABLE TUYENDUNG (MATD TEXT PRIMARY KEY, IDCN TEXT, VITRITD TEXT, DOTUOI INTEGER, GIOITINH TEXT, SOLUONG INTEGER, HANTD TEXT, LUONGTOITHIEU REAL, LUONGTOIDA REAL, SOHOSODANAOP INTEGER, SOHOSODATUYEN INTEGER, TRANGTHAI TEXT, IsDeleted INTEGER DEFAULT 0);
CREATE TABLE UNGVIEN_UNGTUYEN (IDUV TEXT, IDTD TEXT, NGAYUT TEXT, PRIMARY KEY (IDUV, IDTD));
CREATE TABLE NHOMQUYEN (IDNQ TEXT PRIMARY KEY, TENNHOMQUYEN TEXT, MOTA TEXT);
CREATE TABLE TAIKHOAN (IDTK TEXT PRIMARY KEY, TENTK TEXT, PASSWORD TEXT, QUYEN TEXT, IDNV TEXT UNIQUE);










